using System;
using System.Diagnostics;
using System.IO;

public void GeneratePdf(string htmlFilePath, string pdfOutputPath, string pageSize = "A4", string orientation = "Portrait")
{
    var wkhtmltopdfPath = "path_to_your_wkhtmltopdf"; // Replace with the path to your wkhtmltopdf executable
    var arguments = $"--page-size {pageSize} --orientation {orientation} {htmlFilePath} {pdfOutputPath}";

    ProcessStartInfo startInfo = new ProcessStartInfo
    {
        FileName = wkhtmltopdfPath,
        Arguments = arguments,
        RedirectStandardOutput = true,
        UseShellExecute = false,
        CreateNoWindow = true
    };

    using (Process process = new Process())
    {
        process.StartInfo = startInfo;
        process.Start();

        process.WaitForExit();

        if (process.ExitCode == 0)
        {
            Console.WriteLine("PDF generated successfully.");
        }
        else
        {
            Console.WriteLine($"Error generating PDF: Exit code {process.ExitCode}");
        }
    }
}